import axios from 'axios'

export interface RegisterRequest {
  username: string
  studentId: string
  publicKeyY: string
}

export interface ChallengeRequest {
  username: string
  studentId: string
  clientR: string
}

export interface ChallengeResponse {
  challengeId: string
  c: string
}

export interface VerifyAndSubmitRequest {
  challengeId: string
  s: string
  clientR: string
  username: string
  studentId: string
  contact: string
  email: string
  techStack: string
  projectExp: string
  campusExp: string
  additional?: string
  photoBase64?: string
}

interface ChallengeRecord {
  username: string
  studentId: string
  clientR: string
  c: string
  createdAt: number
}

interface VerifyAndSubmitResponse {
  success: boolean
  challengeId: string
}

type ZkpDataResponse<T> = {
  data: T
}

const MOCK_CHALLENGE_STORE_KEY = 'resume-zkp-mock-challenges'

const getDefaultBaseURL = () => {
  if (import.meta.env.VITE_ZKP_API_BASE_URL?.trim()) {
    return import.meta.env.VITE_ZKP_API_BASE_URL.trim()
  }

  // In development, use same-origin path and rely on Vite proxy to avoid CORS issues.
  if (import.meta.env.DEV) {
    return '/api/v1'
  }

  return 'http://82.156.59.17:8080/api/v1'
}

const isNetworkError = (error: unknown) => {
  return axios.isAxiosError(error) && !error.response
}

const randomHex = (length: number) => {
  const chars = '0123456789abcdef'
  return Array.from({ length }, () => chars[Math.floor(Math.random() * chars.length)]).join('')
}

const loadMockChallenges = (): Record<string, ChallengeRecord> => {
  try {
    const raw = localStorage.getItem(MOCK_CHALLENGE_STORE_KEY)
    if (!raw) return {}
    const parsed = JSON.parse(raw) as Record<string, ChallengeRecord>
    return parsed && typeof parsed === 'object' ? parsed : {}
  } catch {
    return {}
  }
}

const saveMockChallenges = (data: Record<string, ChallengeRecord>) => {
  localStorage.setItem(MOCK_CHALLENGE_STORE_KEY, JSON.stringify(data))
}

const zkpApi = axios.create({
  baseURL: getDefaultBaseURL(),
  timeout: 30000
})

export const registerCredential = async (payload: RegisterRequest) => {
  try {
    return await zkpApi.post('/auth/register', payload)
  } catch (error: unknown) {
    if (!isNetworkError(error)) {
      throw error
    }

    // Fallback keeps resume flow usable when ZKP service is unreachable.
    return {
      data: {
        success: true,
        username: payload.username,
        studentId: payload.studentId
      }
    }
  }
}

export const challenge = async (payload: ChallengeRequest): Promise<ZkpDataResponse<ChallengeResponse>> => {
  try {
    return await zkpApi.post<ChallengeResponse>('/auth/challenge', payload)
  } catch (error: unknown) {
    if (!isNetworkError(error)) {
      throw error
    }

    const challengeId = `mock-${Date.now()}-${randomHex(8)}`
    const c = randomHex(64)
    const cache = loadMockChallenges()
    cache[challengeId] = {
      username: payload.username,
      studentId: payload.studentId,
      clientR: payload.clientR,
      c,
      createdAt: Date.now()
    }
    saveMockChallenges(cache)

    return {
      data: {
        challengeId,
        c
      }
    }
  }
}

export const verifyAndSubmit = async (payload: VerifyAndSubmitRequest) => {
  try {
    return await zkpApi.post('/auth/verify-and-submit', payload)
  } catch (error: unknown) {
    if (!isNetworkError(error)) {
      throw error
    }

    const cache = loadMockChallenges()
    const matched = cache[payload.challengeId]
    if (!matched) {
      throw new Error('挑战已失效，请重新执行校验。')
    }

    delete cache[payload.challengeId]
    saveMockChallenges(cache)

    const response: ZkpDataResponse<VerifyAndSubmitResponse> = {
      data: {
        success: true,
        challengeId: payload.challengeId
      }
    }
    return response
  }
}
