import BN from 'bn.js'

const P_HEX =
  'FFFFFFFFFFFFFFFFC90FDAA22168C234C4C6628B80DC1CD1' +
  '29024E088A67CC74020BBEA63B139B22514A08798E3404DD' +
  'EF9519B3CD3A431B302B0A6DF25F14374FE1356D6D51C245' +
  'E485B576625E7EC6F44C42E9A63A3620FFFFFFFFFFFFFFFF'

export const G = new BN(2)
export const P = new BN(P_HEX, 16)
export const Q = P.subn(1).divn(2)

const randomScalar = (): BN => {
  const cryptoObj = globalThis.crypto
  if (!cryptoObj?.getRandomValues) {
    throw new Error('当前环境不支持安全随机数生成')
  }

  const byteLength = Q.byteLength()
  while (true) {
    const bytes = new Uint8Array(byteLength)
    cryptoObj.getRandomValues(bytes)
    const n = new BN(bytes)
    if (!n.isZero() && n.lt(Q)) {
      return n
    }
  }
}

export const generateKeyPair = (): { x: BN; y: BN } => {
  const x = randomScalar()
  const y = G.toRed(BN.mont(P)).redPow(x).fromRed()
  return { x, y }
}

export const generateRandomR = (): { r: BN; R: BN } => {
  const r = randomScalar()
  const R = G.toRed(BN.mont(P)).redPow(r).fromRed()
  return { r, R }
}

export const computeS = (r: BN, x: BN, c: BN): BN => {
  return r.add(x.mul(c)).mod(Q)
}

export const bnToHex = (bn: BN): string => {
  return bn.toString(16).padStart(bn.byteLength() * 2, '0')
}

export const parseHex = (hex: string): BN => {
  return new BN(hex.replace(/^0x/i, ''), 16)
}
